oxy_webhelp_navlinks = {"mysql_protection_config-d30753e31385":{"topics":[{"title":"Creating custom SLA Domains for MySQL","shortdesc":"<p class=\"shortdesc\">Create a custom SLA Domain for MySQL to streamline and customize protection and         recovery plans for MySQL instances.<\/p>","href":"mysql\/mysql_creating_custom_sla_domain.html","attributes":{"data-id":"mysql_creating_custom_sla_domain"},"menu":{"hasChildren":false},"tocID":"mysql_creating_custom_sla_domain-d30753e31396","topics":[]},{"title":"Assigning protection to MySQL instances","shortdesc":"<p class=\"shortdesc\">You can assign a data protection policy to a MySQL instance to protect data against         accidental deletion, corruption, and cyber threats.<\/p>","href":"mysql\/mysql_instance_assigning_protection.html","attributes":{"data-id":"mysql_instance_assigning_protection"},"menu":{"hasChildren":false},"tocID":"mysql_instance_assigning_protection-d30753e31407","topics":[]},{"title":"Editing MySQL SLA Domains","shortdesc":"<p class=\"shortdesc\">Edit an SLA Domain to change the backup and recovery objectives of the associated         MySQL instances.<\/p>","href":"mysql\/mysql_editing_sla_domain.html","attributes":{"data-id":"mysql_editing_sla_domain"},"menu":{"hasChildren":false},"tocID":"mysql_editing_sla_domain-d30753e31418","topics":[]},{"title":"Deleting MySQL SLA Domains","shortdesc":"<p class=\"shortdesc\">Delete an SLA Domain created for MySQL when it is no longer needed.<\/p>","href":"mysql\/mysql_deleting_sla_domain.html","attributes":{"data-id":"mysql_deleting_sla_domain"},"menu":{"hasChildren":false},"tocID":"mysql_deleting_sla_domain-d30753e31429","topics":[]},{"title":"Cloning MySQL SLA Domains","shortdesc":"<p class=\"shortdesc\">Clone an existing SLA Domain to save time by avoiding having to create and configure         a new SLA Domain from scratch. Instead, you can make any necessary adjustments to the cloned         SLA Domain.<\/p>","href":"mysql\/mysql_cloning_sla_domain.html","attributes":{"data-id":"mysql_cloning_sla_domain"},"menu":{"hasChildren":false},"tocID":"mysql_cloning_sla_domain-d30753e31440","topics":[]},{"title":"Synchronizing SLA Domains with a Rubrik cluster","shortdesc":"<p class=\"shortdesc\">Synchronize an SLA Domain with a Rubrik cluster to take on-demand snapshots and to         maintain data protection during ransomware recovery.<\/p>","href":"mysql\/mysql_syncing_sla_domain_rubrik_cluster.html","attributes":{"data-id":"mysql_syncing_sla_domain_rubrik_cluster"},"menu":{"hasChildren":false},"tocID":"mysql_syncing_sla_domain_rubrik_cluster-d30753e31451","topics":[]},{"title":"Taking on-demand snapshots of MySQL instances","shortdesc":"<p class=\"shortdesc\">You can take a full snapshot of MySQL instances by using the on-demand snapshot         method.<\/p>","href":"mysql\/mysql_instance_taking_ods.html","attributes":{"data-id":"mysql_instance_taking_ods"},"menu":{"hasChildren":false},"tocID":"mysql_instance_taking_ods-d30753e31462","topics":[]},{"title":"Legal hold for MySQL snapshots","shortdesc":"<p class=\"shortdesc\">Legal hold ensures that snapshots required for litigation are protected for the         duration of the legal hold, providing a compliant and efficient way to manage data subject         to legal obligations.<\/p>","href":"mysql\/mysql_legal_hold_snapshots.html","attributes":{"data-id":"mysql_legal_hold_snapshots"},"menu":{"hasChildren":false},"tocID":"mysql_legal_hold_snapshots-d30753e31473","next":"mysql_legal_hold_snapshots-d30753e31473"},{"title":"Changing the retention policy of MySQL snapshots","shortdesc":"<p class=\"shortdesc\">Change the retention period of individual MySQL snapshots to optimize storage and         data accessibility of MySQL snapshots.<\/p>","href":"mysql\/mysql_changing_retention_policy.html","attributes":{"data-id":"mysql_changing_retention_policy"},"menu":{"hasChildren":false},"tocID":"mysql_changing_retention_policy-d30753e31506","topics":[]},{"title":"Deleting MySQL snapshots","shortdesc":"<p class=\"shortdesc\">Delete MySQL snapshots that are no longer required for data protection.<\/p>","href":"mysql\/mysql_deleting_snapshots.html","attributes":{"data-id":"mysql_deleting_snapshots"},"menu":{"hasChildren":false},"tocID":"mysql_deleting_snapshots-d30753e31517","topics":[]},{"title":"Object-level pause and resume for MySQL protection","shortdesc":"<p class=\"shortdesc\">You can temporarily pause and resume protection for individual MySQL instances         without affecting the protection of other objects managed by the same SLA         Domain.<\/p>","href":"mysql\/mysql_obj_level_pause_protection.html","attributes":{"data-id":"mysql_obj_level_pause_protection"},"menu":{"hasChildren":false},"tocID":"mysql_obj_level_pause_protection-d30753e31529","next":"mysql_obj_level_pause_protection-d30753e31529"}]}};